import { IMessageComposer } from '@nitrots/nitro-renderer';

export class RequestTokenStoreComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor() {
        // no args needed — just a simple request packet
        this._data = [];

        console.log('[📤] RequestTokenStoreComposer packet sent');
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
